import{c as t,S as i,j as h,m as a}from"./chunks/framework.8aa1YH_s.js";const d=JSON.parse('{"title":"Đăng nhập và Đăng ký","description":"","frontmatter":{},"headers":[],"relativePath":"gioi-thieu/dang-nhap.md","filePath":"gioi-thieu/dang-nhap.md","lastUpdated":0}'),o={name:"gioi-thieu/dang-nhap.md"};function l(g,n,r,e,c,s){return i(),h("div",null,[...n[0]||(n[0]=[a('<h1 id="đang-nhap-va-đang-ky" tabindex="-1">Đăng nhập và Đăng ký <a class="header-anchor" href="#đang-nhap-va-đang-ky" aria-label="Permalink to “Đăng nhập và Đăng ký”">​</a></h1><p>Hệ thống có <strong>3 cổng đăng nhập</strong> cho 3 vai trò. Chọn đúng cổng tương ứng với vai trò của bạn.</p><h2 id="_1-hoc-vien" tabindex="-1">1. Học viên <a class="header-anchor" href="#_1-hoc-vien" aria-label="Permalink to “1. Học viên”">​</a></h2><h3 id="đang-ky-tai-khoan-moi" tabindex="-1">Đăng ký tài khoản mới <a class="header-anchor" href="#đang-ky-tai-khoan-moi" aria-label="Permalink to “Đăng ký tài khoản mới”">​</a></h3><ol><li>Truy cập trang chủ hệ thống.</li><li>Bấm <strong>Đăng ký</strong> ở góc phải trên cùng (hoặc vào trang <code>https://lamsonedutech.vn/auth/hocvien</code> rồi chọn tab Đăng ký).</li><li>Điền các thông tin bắt buộc: <ul><li>Họ và tên</li><li>Số điện thoại (dùng để đăng nhập và nhận OTP)</li><li>Email</li><li>Mật khẩu (ít nhất 6 ký tự, nên có cả chữ và số)</li><li>Xác nhận mật khẩu</li></ul></li><li>Đồng ý điều khoản sử dụng → bấm <strong>Đăng ký</strong>.</li><li>Hệ thống có thể gửi mã OTP qua SMS/email để xác thực số điện thoại / email. Nhập OTP để kích hoạt tài khoản.</li></ol><h3 id="đang-nhap" tabindex="-1">Đăng nhập <a class="header-anchor" href="#đang-nhap" aria-label="Permalink to “Đăng nhập”">​</a></h3><ol><li>Vào trang <code>https://lamsonedutech.vn/auth/hocvien</code>.</li><li>Nhập <strong>số điện thoại / email</strong> và <strong>mật khẩu</strong>.</li><li>Bấm <strong>Đăng nhập</strong>.</li><li>Nếu chọn <strong>Ghi nhớ đăng nhập</strong>, lần sau vào hệ thống không cần đăng nhập lại trên cùng trình duyệt.</li></ol><h3 id="quen-mat-khau" tabindex="-1">Quên mật khẩu <a class="header-anchor" href="#quen-mat-khau" aria-label="Permalink to “Quên mật khẩu”">​</a></h3><ol><li>Tại trang đăng nhập, bấm <strong>Quên mật khẩu</strong>.</li><li>Nhập số điện thoại / email đã đăng ký.</li><li>Nhập mã OTP được gửi tới.</li><li>Đặt mật khẩu mới và đăng nhập lại.</li></ol><h2 id="_2-giao-vien" tabindex="-1">2. Giáo viên <a class="header-anchor" href="#_2-giao-vien" aria-label="Permalink to “2. Giáo viên”">​</a></h2><blockquote><p>Tài khoản giáo viên do <strong>Quản trị viên</strong> cấp. Giáo viên không tự đăng ký.</p></blockquote><ol><li>Sau khi Admin tạo tài khoản, bạn sẽ nhận <strong>email/SMS</strong> chứa: <ul><li>Tên đăng nhập (thường là số điện thoại hoặc email)</li><li>Mật khẩu mặc định</li><li>Đường dẫn đăng nhập: <code>https://lamsonedutech.vn/auth/giaovien</code></li></ul></li><li>Đăng nhập lần đầu → hệ thống có thể yêu cầu <strong>đổi mật khẩu</strong> và <strong>bổ sung hồ sơ</strong> (ảnh đại diện, môn dạy, giới thiệu...).</li><li>Sau đó bạn vào được trang <code>https://lamsonedutech.vn/teacher/dashboard</code>.</li></ol><h2 id="_3-quan-tri-vien" tabindex="-1">3. Quản trị viên <a class="header-anchor" href="#_3-quan-tri-vien" aria-label="Permalink to “3. Quản trị viên”">​</a></h2><blockquote><p>Tài khoản admin do <strong>Quản trị cấp cao hơn</strong> tạo. Khi triển khai lần đầu, hệ thống có một tài khoản admin gốc.</p></blockquote><ol><li>Vào trang <code>https://lamsonedutech.vn/auth/admin</code>.</li><li>Nhập tên đăng nhập / email và mật khẩu.</li><li>Sau đăng nhập, vào trang <code>https://lamsonedutech.vn/admin/dashboard</code>.</li></ol><h2 id="đang-xuat" tabindex="-1">Đăng xuất <a class="header-anchor" href="#đang-xuat" aria-label="Permalink to “Đăng xuất”">​</a></h2><p>Ở mọi vai trò, bấm vào <strong>avatar / tên người dùng</strong> ở góc trên bên phải → chọn <strong>Đăng xuất</strong>.</p><blockquote><p>💡 Sau khi đăng xuất, mọi tab đang mở của hệ thống đều cần đăng nhập lại để tiếp tục.</p></blockquote><h2 id="đoi-mat-khau" tabindex="-1">Đổi mật khẩu <a class="header-anchor" href="#đoi-mat-khau" aria-label="Permalink to “Đổi mật khẩu”">​</a></h2><ul><li><strong>Học viên:</strong> vào <code>https://lamsonedutech.vn/luyen-tap/nguoi-dung/profile</code> → tab <strong>Đổi mật khẩu</strong>.</li><li><strong>Giáo viên:</strong> vào <code>https://lamsonedutech.vn/teacher/profile</code> → <strong>Đổi mật khẩu</strong>.</li><li><strong>Admin:</strong> vào <code>https://lamsonedutech.vn/admin/profile</code> → <strong>Đổi mật khẩu</strong>.</li></ul><h2 id="su-co-thuong-gap" tabindex="-1">Sự cố thường gặp <a class="header-anchor" href="#su-co-thuong-gap" aria-label="Permalink to “Sự cố thường gặp”">​</a></h2><ul><li><strong>Sai mật khẩu nhiều lần:</strong> Tài khoản có thể bị tạm khóa vài phút. Đợi và thử lại, hoặc dùng <strong>Quên mật khẩu</strong>.</li><li><strong>Không nhận được OTP:</strong> Kiểm tra hộp thư rác, chắc chắn nhập đúng số điện thoại / email. Nếu vẫn không có, bấm <strong>Gửi lại</strong> sau ~60 giây.</li><li><strong>Bị đăng xuất khi đang làm bài thi:</strong> Tránh đăng nhập trên nhiều thiết bị cùng lúc. Bài thi sẽ được lưu nháp, có thể tiếp tục nếu còn thời gian.</li><li><strong>Quên cả mật khẩu và số điện thoại:</strong> Liên hệ bộ phận hỗ trợ (mục <strong>Liên hệ</strong> ở footer).</li></ul>',22)])])}const m=t(o,[["render",l]]);export{d as __pageData,m as default};
